use actix_files::Files;
use actix_web::{web, App, HttpServer, Responder};
use std::path::Path;

async fn serve_file(filename: web::Path<String>) -> impl Responder {
    let path = Path::new("uploads").join(&filename);
    if path.exists() && path.is_file() {
        Files::new("/", "uploads").serve_file(path).await
    } else {
        web::HttpResponse::NotFound().body("File not found")
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/files/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}